class Generator(nn.Module):
    def __init__(self):
        super().__init__()
        self.network = nn.Sequential(
            nn.Linear(128, 256),
            nn.ReLU(),
            nn.Linear(256, 512),
            nn.ReLU(),
            nn.Linear(512, 784),
            nn.Tanh()  # Output range [-1, 1]
        )

    def forward(self, x):
        return self.network(x)

# Example: GAN Discriminator
class Discriminator(nn.Module):
    def __init__(self):
        super().__init__()
        self.network = nn.Sequential(
            nn.Linear(784, 512),
            nn.LeakyReLU(0.2),
            nn.Linear(512, 256),
            nn.LeakyReLU(0.2),
            nn.Linear(256, 1),
            nn.Sigmoid()
        )

    def forward(self, x):
        return self.network(x)

class DiffusionModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.embedding = nn.Linear(784, 512)
        self.layers = nn.Sequential(
            nn.ReLU(),
            nn.Linear(512, 512),
            nn.ReLU(),
            nn.Linear(512, 784)
        )
        self.time_embed = nn.Linear(1, 512)

    def forward(self, x, t):
        x_emb = self.embedding(x)
        t_emb = self.time_embed(t)
        return self.layers(x_emb + t_emb)

