import torch
import torch.nn as nn

# MISTAKE 1: calling forward() directly instead of the module instance
class BadModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.fc = nn.Linear(10, 5)
    def forward(self, x):
        return self.fc(x)

model = BadModel()
x = torch.randn(2, 10)
# WRONG: bypasses __call__, hooks never fire
out = model.forward(x)
# CORRECT:
out = model(x)

# MISTAKE 2: registering a list of modules without nn.ModuleList
class AlsoWrong(nn.Module):
    def __init__(self):
        super().__init__()
        # Python list — parameters NOT tracked!
        self.layers = [nn.Linear(10, 10) for _ in range(3)]
    def forward(self, x):
        for l in self.layers: x = l(x)
        return x

wrong = AlsoWrong()
print(list(wrong.parameters()))  # [] — empty! Optimizer sees nothing.

class Fixed(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.ModuleList([nn.Linear(10, 10) for _ in range(3)])
    def forward(self, x):
        for l in self.layers: x = l(x)
        return x

fixed = Fixed()
print(len(list(fixed.parameters())))  # 6 (3 weights + 3 biases)

# MISTAKE 3: forgetting super().__init__()
class Broken(nn.Module):
    def __init__(self):
        # Missing super().__init__()  ← AttributeError on self.fc assignment
        self.fc = nn.Linear(10, 5)
    def forward(self, x):
        return self.fc(x)

# MISTAKE 4: using model.eval() but forgetting torch.no_grad()
model.eval()            # disables dropout/batchnorm training mode
out = model(x)          # still builds computation graph — wastes memory
# Correct inference:
with torch.no_grad():
    out = model(x)      # no gradient tape allocated
